/**
 * Get failed tests with AI context for analysis
 * Supports filtering by error type, test file, or date range
 */
export async function getFailuresWithAIContext(
  options: {
    errorType?: string
    testFile?: string
    limit?: number
    since?: string
  } = {}
): Promise<TestResult[]> {
  const { errorType, testFile, limit = 50, since } = options

  let query = `
    SELECT
      id, execution_id, test_name, test_file, test_signature,
      status, duration_ms, is_critical, error_message, stack_trace,
      browser, retry_count, ai_context, created_at
    FROM test_results
    WHERE ai_context IS NOT NULL
    AND status IN ('failed', 'timedout')
  `

  const values: any[] = []
  let paramIndex = 1

  if (errorType) {
    query += ` AND ai_context->'error'->>'type' = $${paramIndex}`
    values.push(errorType)
    paramIndex++
  }

  if (testFile) {
    query += ` AND test_file ILIKE $${paramIndex}`
    values.push(`%${testFile}%`)
    paramIndex++
  }

  if (since) {
    query += ` AND created_at >= $${paramIndex}`
    values.push(since)
    paramIndex++
  }

  query += ` ORDER BY created_at DESC LIMIT $${paramIndex}`
  values.push(limit)

  const result = await pool.query(query, values)
  return result.rows
}

/**
 * Get error type distribution for dashboard analytics
 */
export async function getErrorTypeDistribution(
  since?: string
): Promise<Array<{ error_type: string; count: number }>> {
  let query = `
    SELECT
      ai_context->'error'->>'type' as error_type,
      COUNT(*) as count
    FROM test_results
    WHERE ai_context IS NOT NULL
    AND status IN ('failed', 'timedout')
  `

  const values: any[] = []

  if (since) {
    query += ` AND created_at >= $1`
    values.push(since)
  }

  query += `
    GROUP BY ai_context->'error'->>'type'
    ORDER BY count DESC
  `

  const result = await pool.query(query, values)
  return result.rows
}
